@app.route('/saml/login')
def saml_login():
    """Initiate SAML SSO by redirecting to the IdP."""
    request_id, authn_request_xml = create_authn_request()

    # Store request ID in session for validation
    session['authn_request_id'] = request_id

    # Base64 encode the request
    encoded_request = base64.b64encode(authn_request_xml.encode('utf-8')).decode('utf-8')

    relay_state = session.pop('relay_state', url_for('dashboard'))

    # Build the redirect URL (HTTP-Redirect binding)
    # In production, you'd also deflate-compress the request
    html = f'''
    <!DOCTYPE html>
    <html>
    <head><title>Redirecting to IdP...</title></head>
    <body>
        <h2>Redirecting to Identity Provider...</h2>
        <form id="saml-form" method="POST" action="{SAML_CONFIG['idp_sso_url']}">
            <input type="hidden" name="SAMLRequest" value="{encoded_request}" />
            <input type="hidden" name="RelayState" value="{relay_state}" />
            <noscript>
                <p>JavaScript is disabled. Click the button below to continue.</p>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
        <script>document.getElementById('saml-form').submit();</script>
    </body>
    </html>
    '''
    return html


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - Process SAML Response from IdP."""
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', url_for('dashboard'))

    if not saml_response_b64:
        return jsonify({'error': 'No SAMLResponse found in request'}), 400

    try:
        parser = SAMLResponseParser(saml_response_b64)
        is_valid = parser.parse()

        if not is_valid:
            app.logger.error(f'SAML Response validation failed: {parser.errors}')
            return jsonify({
                'error': 'SAML Response validation failed',
                'details': parser.errors
            }), 400

        # Validate the response issuer matches our IdP
        if parser.issuer and parser.issuer != SAML_CONFIG['idp_entity_id']:
            app.logger.error(
                f'Issuer mismatch: expected {SAML_CONFIG["idp_entity_id"]}, '
                f'got {parser.issuer}'
            )
            return jsonify({
                'error': 'Issuer mismatch',
                'expected': SAML_CONFIG['idp_entity_id'],
                'received': parser.issuer
            }), 400

        # Extract user data and create session
        user_data = parser.get_user_data()

        # Create the session
        session.permanent = True
        session['user'] = user_data
        session['saml_session_index'] = user_data.get('session_index', '')
        session['saml_name_id'] = user_data.get('name_id', '')
        session['authenticated_at'] = datetime.utcnow().isoformat()
        session['session_id'] = str(uuid.uuid4())

        # Store in our session store
        user_sessions[session['session_id']] = {
            'user': user_data,
            'created_at': datetime.utcnow().isoformat(),
            'saml_session_index': user_data.get('session_index', ''),
        }

        app.logger.info(
            f'User authenticated via SAML: {user_data.get("email", user_data.get("name_id"))}'
        )

        return redirect(relay_state)

    except ET.ParseError as e:
        app.logger.error(f'XML Parse Error: {e}')
        return jsonify({'error': 'Invalid SAML XML response', 'details': str(e)}), 400
    except Exception as e:
        app.logger.error(f'SAML ACS Error: {e}')
        return jsonify({'error': 'Error processing SAML response', 'details': str(e)}), 500


@app.route('/saml/slo', methods=['GET', 'POST'])
def saml_slo():
    """Single Logout Service - Process logout from IdP or initiate logout."""
    if request.method == 'POST':
        # IdP-initiated logout
        saml_request_b64 = request.form.get('SAMLRequest')
        if saml_request_b64:
            try:
                xml_bytes = base64.b64decode(saml_request_b64)
                root = ET.fromstring(xml_bytes.decode('utf-8'))

                # Extract the session index to find the right session
                session_index = root.find(
                    './/samlp:SessionIndex', SAML_NAMESPACES
                )
                if session_index is not None:
                    # Find and remove matching sessions
                    sessions_to_remove = []
                    for sid, sdata in user_sessions.items():
                        if sdata.get('saml_session_index') == session_index.text:
                            sessions_to_remove.append(sid)
                    for sid in sessions_to_remove:
                        del user_sessions[sid]

                session.clear()
                app.logger.info('User logged out via IdP-initiated SLO')

                # Send LogoutResponse back to IdP
                return redirect(SAML_CONFIG['idp_slo_url'])

            except Exception as e:
                app.logger.error(f'SLO Error: {e}')
                session.clear()
                return redirect(url_for('index'))

    # SP-initiated logout
    return redirect(url_for('saml_logout'))


@app.route('/saml/logout')
def saml_logout():
    """Initiate SP logout."""
    name_id = session.get('saml_name_id', '')
    session_index = session.get('saml_session_index', '')
    session_id = session.get('session_id', '')

    # Remove from session store
    if session_id in user_sessions:
        del user_sessions[session_id]

    # Clear Flask session
    session.clear()

    if name_id and session_index:
        # Create LogoutRequest to IdP
        request_id, logout_request_xml = create_logout_request(name_id, session_index)
        encoded_request = base64.b64encode(
            logout_request_xml.encode('utf-8')
        ).decode('utf-8')

        html = f'''
        <!DOCTYPE html>
        <html>
        <head><title>Logging out...</title></head>
        <body>
            <h2>Logging out...</h2>
            <form id="logout-form" method="POST" action="{SAML_CONFIG['idp_slo_url']}">
                <input type="hidden" name="SAMLRequest" value="{encoded_request}" />
                <input type="hidden" name="RelayState" value="{url_for('index', _external=True)}" />
                <noscript>
                    <input type="submit" value="Continue Logout" />
                </noscript>
            </form>
            <script>document.getElementById('logout-form').submit();</script>
        </body>
        </html>
        '''
        return html

    return redirect(url_for('index'))


