# ============================================================
# Test/Development helper route
# ============================================================

@app.route('/saml/test', methods=['GET', 'POST'])
def saml_test():
    """Test endpoint to simulate SAML response (development only)."""
    if request.method == 'POST':
        # Create a mock SAML response for testing
        mock_response = create_mock_saml_response()
        encoded = base64.b64encode(mock_response.encode('utf-8')).decode('utf-8')

        # Redirect to ACS with mock response
        html = f'''
        <form id="test-form" method="POST" action="{url_for('saml_acs')}">
            <input type="hidden" name="SAMLResponse" value="{encoded}" />
            <input type="hidden" name="RelayState" value="{url_for('dashboard')}" />
        </form>
        <script>document.getElementById('test-form').submit();</script>
        '''
        return html

    html = '''
    <!DOCTYPE html>
    <html>
    <head><title>SAML Test</title></head>
    <body>
        <h1>SAML Test Page</h1>
        <p>This will create a mock SAML response for testing.</p>
        <form method="POST">
            <button type="submit">Simulate SAML Login</button>
        </form>
    </body>
    </html>
    '''
    return html


def create_mock_saml_response():
    """Create a mock SAML response for testing purposes."""
    now = datetime.utcnow()
    not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (now + timedelta(hours=1)).strftime('%Y-%m-%dT%H:%M:%SZ')
    issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')
    response_id = f'_{uuid.uuid4().hex}'
    assertion_id = f'_{uuid.uuid4().hex}'
    session_index = f'_{uuid.uuid4().hex}'

    return f'''<?xml version="1.0" encoding="UTF-8"?>
<samlp:Response
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{response_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['sp_acs_url']}"
    InResponseTo="_test123">
    <saml:Issuer>{SAML_CONFIG['idp_entity_id']}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
    <saml:Assertion
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{assertion_id}"
        IssueInstant="{issue_instant}"
        Version="2.0">
        <saml:Issuer>{SAML_CONFIG['idp_entity_id']}</saml:Issuer>
        <saml:Subject>
            <saml:NameID
                Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
                SPNameQualifier="{SAML_CONFIG['sp_entity_id']}">
                testuser@example.com
            </saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData
                    InResponseTo="_test123"
                    NotOnOrAfter="{not_on_or_after}"
                    Recipient="{SAML_CONFIG['sp_acs_url']}"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>{SAML_CONFIG['sp_entity_id']}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement
            AuthnInstant="{issue_instant}"
            SessionIndex="{session_index}"
            SessionNotOnOrAfter="{not_on_or_after}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>
                    urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport
                </saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress"
                            FriendlyName="email">
                <saml:AttributeValue>testuser@example.com</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname"
                            FriendlyName="first_name">
                <saml:AttributeValue>Test</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname"
                            FriendlyName="last_name">
                <saml:AttributeValue>User</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name"
                            FriendlyName="display_name">
                <saml:AttributeValue>Test User</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.microsoft.com/ws/2008/06/identity/claims/role"
                            FriendlyName="roles">
                <saml:AttributeValue>admin</saml:AttributeValue>
                <saml:AttributeValue>user</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="http://schemas.xmlsoap.org/claims/Group"
                            FriendlyName="groups">
                <saml:AttributeValue>Engineering</saml:AttributeValue>
                <saml:AttributeValue>Developers</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="department" FriendlyName="department">
                <saml:AttributeValue>Engineering</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="employee_id" FriendlyName="employee_id">
                <saml:AttributeValue>EMP-12345</saml:AttributeValue>
            </saml:Attribute>
        </saml:AttributeStatement>
    </saml:Assertion>
</samlp:Response>'''


